#!/usr/bin/env node
// Generates mcp/tools.json from mcp/openapi-readonly.json
// Output: MCP tools/list payload + TOOL_ROUTES mapping for tools/call dispatch

import { readFileSync, writeFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const specPath = join(__dirname, "openapi-readonly.json");
const outPath = join(__dirname, "tools.json");

const spec = JSON.parse(readFileSync(specPath, "utf8"));

const tools = [];
const toolRoutes = {};

for (const [pathTemplate, methods] of Object.entries(spec.paths)) {
  for (const [method, op] of Object.entries(methods)) {
    if (!op.operationId) continue;

    const pathParams = [];
    const properties = {};
    const required = [];

    for (const param of op.parameters || []) {
      const prop = { type: param.schema?.type || "string" };
      if (param.description) prop.description = param.description;
      if (param.schema?.enum) prop.enum = param.schema.enum;
      if (param.schema?.default !== undefined) prop.default = param.schema.default;
      if (param.schema?.minimum !== undefined) prop.minimum = param.schema.minimum;

      properties[param.name] = prop;

      if (param.in === "path") {
        pathParams.push(param.name);
        required.push(param.name);
      } else if (param.required) {
        required.push(param.name);
      }
    }

    const inputSchema = { type: "object", properties };
    if (required.length) inputSchema.required = required;

    const description = [op.summary, op.description]
      .filter(Boolean)
      .join(". ")
      .replace(/\.\./g, ".");

    tools.push({ name: op.operationId, description, inputSchema });

    toolRoutes[op.operationId] = {
      path: pathTemplate,
      method: method.toUpperCase(),
      pathParams,
    };
  }
}

const output = { tools, toolRoutes };
writeFileSync(outPath, JSON.stringify(output, null, 2) + "\n");

console.log(`Generated ${tools.length} tools → ${outPath}`);

