// MCP JSON-RPC 2.0 handler for the admin API Lambda.
// Handles initialize, tools/list, and tools/call by dispatching
// tool calls to the existing REST handler via synthetic events.

import { readFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const { tools, toolRoutes } = JSON.parse(
  readFileSync(join(__dirname, "tools.json"), "utf8")
);

const PROTOCOL_VERSION = "2025-03-26";
const SERVER_INFO = { name: "agent-hal", version: "1.0.0" };

/**
 * Handle an MCP JSON-RPC 2.0 request.
 * @param {object} body  — parsed JSON-RPC request
 * @param {object} event — original API Gateway event (for auth forwarding)
 * @param {Function} handler — the admin API handler function (for recursive dispatch)
 * @returns {object} JSON-RPC 2.0 response
 */
export async function handleMcp(body, event, handler) {
  const { jsonrpc, id, method, params } = body;

  if (jsonrpc !== "2.0") {
    return { jsonrpc: "2.0", id: id ?? null, error: { code: -32600, message: "Invalid Request — expected jsonrpc 2.0" } };
  }

  // Notifications (no id) — acknowledge silently
  if (id === undefined || id === null) {
    return null; // no response for notifications
  }

  switch (method) {
    case "initialize":
      return {
        jsonrpc: "2.0",
        id,
        result: {
          protocolVersion: PROTOCOL_VERSION,
          capabilities: { tools: { listChanged: false } },
          serverInfo: SERVER_INFO,
        },
      };

    case "notifications/initialized":
      return null;

    case "tools/list":
      return { jsonrpc: "2.0", id, result: { tools } };

    case "tools/call":
      return callTool(id, params, event, handler);

    default:
      return { jsonrpc: "2.0", id, error: { code: -32601, message: `Method not found: ${method}` } };
  }
}

async function callTool(id, params, outerEvent, handler) {
  const { name, arguments: args = {} } = params || {};
  const route = toolRoutes[name];

  if (!route) {
    return {
      jsonrpc: "2.0",
      id,
      error: { code: -32602, message: `Unknown tool: ${name}` },
    };
  }

  // Build path with substituted path params
  let path = route.path;
  for (const p of route.pathParams) {
    const val = args[p];
    if (val === undefined || val === null) {
      return {
        jsonrpc: "2.0",
        id,
        error: { code: -32602, message: `Missing required parameter: ${p}` },
      };
    }
    path = path.replace(`{${p}}`, encodeURIComponent(String(val)));
  }

  // Non-path args become query parameters
  const queryParams = {};
  for (const [k, v] of Object.entries(args)) {
    if (!route.pathParams.includes(k) && v !== undefined && v !== null) {
      queryParams[k] = String(v);
    }
  }

  // Build synthetic API Gateway event — reuse auth headers from the outer event
  const syntheticEvent = {
    path,
    httpMethod: route.method,
    headers: outerEvent.headers,
    queryStringParameters: Object.keys(queryParams).length ? queryParams : null,
    requestContext: outerEvent.requestContext,
  };

  try {
    const response = await handler(syntheticEvent);
    const statusCode = response.statusCode || 200;

    if (statusCode >= 400) {
      const errBody = tryParseJson(response.body);
      return {
        jsonrpc: "2.0",
        id,
        result: {
          content: [{ type: "text", text: JSON.stringify(errBody || { error: `HTTP ${statusCode}` }) }],
          isError: true,
        },
      };
    }

    return {
      jsonrpc: "2.0",
      id,
      result: {
        content: [{ type: "text", text: response.body || "{}" }],
      },
    };
  } catch (err) {
    return {
      jsonrpc: "2.0",
      id,
      error: { code: -32603, message: `Internal error: ${err.message}` },
    };
  }
}

function tryParseJson(str) {
  try { return JSON.parse(str); } catch { return null; }
}

