# ══════════════════════════════════════════════════════════════════════════════
# Regional (public) API Gateway — MCP endpoint for Claude Code
# ══════════════════════════════════════════════════════════════════════════════
#
# Exposes the MCP JSON-RPC endpoint and OAuth discovery endpoint.
# Authentication is handled by the Lambda (Okta JWT validation), not
# the API Gateway. Claude Code auto-discovers Okta via the well-known
# endpoint and handles the OAuth browser flow natively.
# ══════════════════════════════════════════════════════════════════════════════

resource "aws_api_gateway_rest_api" "mcp" {
  name        = "${local.prefix}-mcp-api"
  description = "MCP endpoint for Agent HAL (Claude Code OAuth flow)"

  endpoint_configuration {
    types = ["REGIONAL"]
  }

  tags = {
    Environment = var.env
    Project     = "agent-hal"
    ManagedBy   = "terraform"
  }
}

# ── /.well-known/oauth-protected-resource (GET, unauthenticated) ────────────
resource "aws_api_gateway_resource" "mcp_well_known" {
  rest_api_id = aws_api_gateway_rest_api.mcp.id
  parent_id   = aws_api_gateway_rest_api.mcp.root_resource_id
  path_part   = ".well-known"
}

resource "aws_api_gateway_resource" "mcp_well_known_oauth" {
  rest_api_id = aws_api_gateway_rest_api.mcp.id
  parent_id   = aws_api_gateway_resource.mcp_well_known.id
  path_part   = "oauth-protected-resource"
}

resource "aws_api_gateway_method" "mcp_well_known_get" {
  rest_api_id   = aws_api_gateway_rest_api.mcp.id
  resource_id   = aws_api_gateway_resource.mcp_well_known_oauth.id
  http_method   = "GET"
  authorization = "NONE"
}

resource "aws_api_gateway_integration" "mcp_well_known_get" {
  rest_api_id             = aws_api_gateway_rest_api.mcp.id
  resource_id             = aws_api_gateway_resource.mcp_well_known_oauth.id
  http_method             = aws_api_gateway_method.mcp_well_known_get.http_method
  type                    = "AWS_PROXY"
  integration_http_method = "POST"
  uri                     = aws_lambda_function.admin_api.invoke_arn
}

# ── /mcp (POST + OPTIONS) ──────────────────────────────────────────────────
resource "aws_api_gateway_resource" "mcp_endpoint" {
  rest_api_id = aws_api_gateway_rest_api.mcp.id
  parent_id   = aws_api_gateway_rest_api.mcp.root_resource_id
  path_part   = "mcp"
}

resource "aws_api_gateway_method" "mcp_post" {
  rest_api_id   = aws_api_gateway_rest_api.mcp.id
  resource_id   = aws_api_gateway_resource.mcp_endpoint.id
  http_method   = "POST"
  authorization = "NONE"
}

resource "aws_api_gateway_integration" "mcp_post" {
  rest_api_id             = aws_api_gateway_rest_api.mcp.id
  resource_id             = aws_api_gateway_resource.mcp_endpoint.id
  http_method             = aws_api_gateway_method.mcp_post.http_method
  type                    = "AWS_PROXY"
  integration_http_method = "POST"
  uri                     = aws_lambda_function.admin_api.invoke_arn
}

resource "aws_api_gateway_method" "mcp_options" {
  rest_api_id   = aws_api_gateway_rest_api.mcp.id
  resource_id   = aws_api_gateway_resource.mcp_endpoint.id
  http_method   = "OPTIONS"
  authorization = "NONE"
}

resource "aws_api_gateway_integration" "mcp_options" {
  rest_api_id             = aws_api_gateway_rest_api.mcp.id
  resource_id             = aws_api_gateway_resource.mcp_endpoint.id
  http_method             = aws_api_gateway_method.mcp_options.http_method
  type                    = "AWS_PROXY"
  integration_http_method = "POST"
  uri                     = aws_lambda_function.admin_api.invoke_arn
}

# ── Deployment & stage ───────────────────────────────────────────────────────
resource "aws_api_gateway_deployment" "mcp" {
  rest_api_id = aws_api_gateway_rest_api.mcp.id

  depends_on = [
    aws_api_gateway_integration.mcp_well_known_get,
    aws_api_gateway_integration.mcp_post,
    aws_api_gateway_integration.mcp_options,
  ]

  triggers = {
    redeployment = sha1(jsonencode([
      aws_api_gateway_resource.mcp_well_known.id,
      aws_api_gateway_resource.mcp_well_known_oauth.id,
      aws_api_gateway_method.mcp_well_known_get.id,
      aws_api_gateway_integration.mcp_well_known_get.id,
      aws_api_gateway_resource.mcp_endpoint.id,
      aws_api_gateway_method.mcp_post.id,
      aws_api_gateway_integration.mcp_post.id,
      aws_api_gateway_method.mcp_options.id,
      aws_api_gateway_integration.mcp_options.id,
    ]))
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_api_gateway_stage" "mcp" {
  rest_api_id   = aws_api_gateway_rest_api.mcp.id
  deployment_id = aws_api_gateway_deployment.mcp.id
  stage_name    = var.env

  tags = {
    Environment = var.env
    Project     = "agent-hal"
    ManagedBy   = "terraform"
  }
}

# ── Allow MCP API Gateway to invoke the admin Lambda ────────────────────────
resource "aws_lambda_permission" "mcp_apigw" {
  statement_id  = "AllowMCPAPIGatewayInvoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.admin_api.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.mcp.execution_arn}/*/*"
}

input.new_string:
  TRACKED_TICKETS_TABLE           = aws_dynamodb_table.tracked_tickets.name
  MCP_RESOURCE_URL                = aws_api_gateway_stage.mcp.invoke_url
}

# ── MCP API ─────────────────────────────────────────────────────────────────
output "mcp_api_invoke_url" {
  description = "MCP API invoke URL (for Claude Code MCP server config)"
  value       = "${aws_api_gateway_stage.mcp.invoke_url}/mcp"
}

# ── Dashboard ────────────────────────────────────────────────────────────────

